class Animal:
    def __init__(self, name):
        self.name = name

    def eat(self):
        print(f"{self.name} is eating.")

class Dog(Animal):
    def speak(self):
        print(f"{self.name} says: Woof!")

fido = Dog("Fido")
fido.speak()

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)  # parent sets self.name
        self.breed = breed

fido = Dog("Fido", "Labrador")
print(fido.name, fido.breed)
